import{_ as e,o as t,c as o,e as n}from"./app-5b072fc4.js";const a={},h=n('<h1 id="do-not-go-gentle-into-that-good-night" tabindex="-1"><a class="header-anchor" href="#do-not-go-gentle-into-that-good-night" aria-hidden="true">#</a> <em>Do not go gentle into that good night</em></h1><p align="right"><i>Dylan Thomas 1914 – 1953</i></p><p>Do not go gentle into that good night, Old age should burn and rave at close of day; Rage, rage against the dying of the light.</p><p>Though wise men at their end know dark is right, Because their words had forked no lightning they Do not go gentle into that good night.</p><p>Good men, the last wave by, crying how bright Their frail deeds might have danced in a green bay, Rage, rage against the dying of the light.</p><p>Wild men who caught and sang the sun in flight, And learn, too late, they grieved it on its way, Do not go gentle into that good night.</p><p>Grave men, near death, who see with blinding sight Blind eyes could blaze like meteors and be gay, Rage, rage against the dying of the light.</p><p>And you, my father, there on the sad height, Curse, bless, me now with your fierce tears, I pray. Do not go gentle into that good night. Rage, rage against the dying of the light.</p><br><blockquote><p>From <em>&quot;The Poems of Dylan Thomas&quot;</em>, published by New Directions.</p><p>Copyright © 1952, 1953 Dylan Thomas.</p><p>Copyright © 1937, 1945, 1955, 1962, 1966, 1967 the Trustees for the Copyrights of Dylan Thomas.</p><p>Copyright © 1938, 1939, 1943, 1946, 1971 New Directions Publishing Corp. Used with permission.</p></blockquote>',10),i=[h];function g(r,s){return t(),o("div",null,i)}const l=e(a,[["render",g],["__file","01_DylanThomas.html.vue"]]);export{l as default};
